import React, { useState, useEffect, useCallback, useRef } from 'react';
import { studentAPI } from '../services/api';
import { useSelector } from 'react-redux';
import toast from 'react-hot-toast';

const STYLES = {
  blue:   { sidebar:'#1E1B4B', accent:'#7C3AED', bg:'#EDE9F8', name:'Classic Blue'   },
  green:  { sidebar:'#065F46', accent:'#10B981', bg:'#D1FAE5', name:'Forest Green'   },
  red:    { sidebar:'#991B1B', accent:'#EF4444', bg:'#FEE2E2', name:'Royal Red'      },
  orange: { sidebar:'#92400E', accent:'#F59E0B', bg:'#FEF3C7', name:'Sunset Orange'  },
};

function CardFront({ student, style, school }) {
  const s = STYLES[style] || STYLES.blue;
  const name = student ? ((student.first_name||'') + ' ' + (student.last_name||'')).trim() : 'Student Name';
  const photo = student?.photo_url || null;
  return (
    <div style={{ width:340, height:200, borderRadius:14, overflow:'hidden', display:'flex', fontFamily:'Plus Jakarta Sans, Arial, sans-serif', background:'#fff', boxShadow:'0 4px 20px rgba(0,0,0,.15)', flexShrink:0 }}>
      {/* Left strip */}
      <div style={{ width:92, background:s.sidebar, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'10px 6px', gap:6, flexShrink:0 }}>
        <div style={{ width:68, height:72, borderRadius:10, background:'rgba(255,255,255,.15)', overflow:'hidden', border:'2px solid rgba(255,255,255,.3)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
          {photo
            ? <img src={photo} alt="photo" style={{ width:'100%', height:'100%', objectFit:'cover' }}/>
            : <div style={{ fontSize:30, color:'rgba(255,255,255,.5)' }}>👤</div>}
        </div>
        <div style={{ width:50, height:50, background:'rgba(255,255,255,.1)', borderRadius:8, display:'flex', alignItems:'center', justifyContent:'center' }}>
          {/* Barcode placeholder */}
          <div style={{ display:'flex', gap:1 }}>
            {[2,1,3,1,2,1,3,2,1,2].map((h,i) => (
              <div key={i} style={{ width:2, height:h*6, background:'rgba(255,255,255,.7)', borderRadius:1 }}/>
            ))}
          </div>
        </div>
      </div>
      {/* Right content */}
      <div style={{ flex:1, display:'flex', flexDirection:'column', justifyContent:'space-between', padding:'12px 14px' }}>
        {/* Header */}
        <div>
          <div style={{ fontSize:7, fontWeight:700, color:s.sidebar, textTransform:'uppercase', letterSpacing:'.1em', marginBottom:1 }}>Student Identity Card</div>
          <div style={{ fontSize:15, fontWeight:800, color:'#111827', lineHeight:1.2, marginBottom:8 }}>{name}</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'2px 8px' }}>
            {[
              ['Class',    student ? (student.class_name||student.cls||'—') : '—'],
              ['Section',  student ? (student.section_name||student.sec||'—') : '—'],
              ['Adm No.',  student ? (student.admission_no||student.adm||'—') : '—'],
              ['Roll No.', student ? (student.roll_no||'—') : '—'],
              ['DOB',      student ? (student.date_of_birth||'—') : '—'],
              ['Blood',    student ? (student.blood_group||'—') : '—'],
            ].map(([k,v]) => (
              <div key={k} style={{ lineHeight:1.7 }}>
                <span style={{ fontSize:8, color:'#9CA3AF' }}>{k}: </span>
                <span style={{ fontSize:9, color:'#374151', fontWeight:600 }}>{v}</span>
              </div>
            ))}
          </div>
        </div>
        {/* Footer */}
        <div style={{ background:s.bg, borderRadius:8, padding:'5px 10px', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <div>
            <div style={{ fontSize:8, fontWeight:700, color:s.sidebar }}>{school?.schoolName||'School Name'}</div>
            <div style={{ fontSize:7, color:'#6B7280' }}>{school?.phone||''}</div>
          </div>
          <div style={{ textAlign:'right' }}>
            <div style={{ fontSize:7, color:'#6B7280' }}>Valid: 2025–26</div>
            <div style={{ fontSize:8, fontWeight:700, color:s.accent }}>✦ EduErpee</div>
          </div>
        </div>
      </div>
    </div>
  );
}

function CardBack({ student, style, school }) {
  const s = STYLES[style] || STYLES.blue;
  return (
    <div style={{ width:340, height:200, borderRadius:14, overflow:'hidden', fontFamily:'Plus Jakarta Sans, Arial, sans-serif', background:'#fff', boxShadow:'0 4px 20px rgba(0,0,0,.15)', display:'flex', flexDirection:'column', justifyContent:'space-between', flexShrink:0 }}>
      <div style={{ background:s.sidebar, padding:'10px 16px' }}>
        <div style={{ color:'rgba(255,255,255,.7)', fontSize:7, textTransform:'uppercase', letterSpacing:'.1em' }}>Student Identity Card — Back</div>
        <div style={{ color:'#fff', fontSize:11, fontWeight:700 }}>{school?.schoolName||'School Name'}</div>
      </div>
      <div style={{ padding:'10px 16px', flex:1, display:'flex', flexDirection:'column', justifyContent:'center', gap:5 }}>
        {[
          ['📍', school?.address||'School Address, City, State'],
          ['📞', school?.phone||'Phone Number'],
          ['✉️', school?.email||'school@email.com'],
          ['🌐', school?.website||'www.school.edu.in'],
        ].map(([icon, val]) => (
          <div key={icon} style={{ display:'flex', gap:6, alignItems:'center', fontSize:9, color:'#374151' }}>
            <span style={{ fontSize:10 }}>{icon}</span>
            <span>{val}</span>
          </div>
        ))}
      </div>
      <div style={{ background:s.bg, padding:'6px 16px', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
        <div style={{ fontSize:8, color:s.sidebar, fontWeight:600 }}>If found, please return to school</div>
        <div style={{ fontSize:8, color:s.sidebar }}>Session: 2025-26</div>
      </div>
    </div>
  );
}

export default function IDCard() {
  const reduxStudents = useSelector(s => s.admission.students);
  const school = React.useMemo(() => {
    try { return JSON.parse(localStorage.getItem('school_settings')) || {}; } catch { return {}; }
  }, []);

  const [students,    setStudents]    = useState([]);
  const [loading,     setLoading]     = useState(false);
  const [selected,    setSelected]    = useState(null);
  const [cardStyle,   setCardStyle]   = useState('blue');
  const [search,      setSearch]      = useState('');
  const [showPrint,   setShowPrint]   = useState(false);
  const [bulkClass,   setBulkClass]   = useState('');
  const [showBulk,    setShowBulk]    = useState(false);
  const printRef = useRef();

  const loadStudents = useCallback(async () => {
    setLoading(true);
    try {
      const res = await studentAPI.getAll({ limit:200 });
      setStudents(res.data.data || []);
    } catch {
      setStudents(reduxStudents.map(s => ({
        id:s.id, admission_no:s.adm,
        first_name:s.name.split(' ')[0], last_name:s.name.split(' ').slice(1).join(' '),
        class_name:s.cls, section_name:s.sec, parent_name:s.parent,
        date_of_birth:s.dob, blood_group:s.blood, photo_url:null,
      })));
    } finally { setLoading(false); }
  }, [reduxStudents]);

  useEffect(() => { loadStudents(); }, [loadStudents]);

  const filtered = students.filter(s => {
    const q = search.toLowerCase();
    const n = ((s.first_name||'') + ' ' + (s.last_name||'')).toLowerCase();
    return !search || n.includes(q) || (s.admission_no||'').toLowerCase().includes(q) || (s.class_name||'').toLowerCase().includes(q);
  });

  const classes = [...new Set(students.map(s => s.class_name).filter(Boolean))].sort();

  // ── Print single card ──────────────────────────────────
  const handlePrint = () => {
    if (!selected) { toast.error('Select a student first'); return; }
    setShowPrint(true);
  };

  const doPrint = () => {
    const s    = STYLES[cardStyle] || STYLES.blue;
    const name = ((selected?.first_name||'') + ' ' + (selected?.last_name||'')).trim();

    // Build card HTML with colors hardcoded directly — no reliance on React inline styles
    const frontHTML = `
      <div style="width:340px;height:200px;border-radius:14px;overflow:hidden;display:flex;font-family:'Plus Jakarta Sans',Arial,sans-serif;background:#fff;box-shadow:0 4px 20px rgba(0,0,0,.15);flex-shrink:0;border:1px solid #E5E7EB;">
        <div style="width:92px;background:${s.sidebar};display:flex;flex-direction:column;align-items:center;justify-content:center;padding:10px 6px;gap:6px;flex-shrink:0;">
          <div style="width:68px;height:72px;border-radius:10px;background:rgba(255,255,255,.15);overflow:hidden;border:2px solid rgba(255,255,255,.3);display:flex;align-items:center;justify-content:center;">
            ${selected?.photo_url
              ? `<img src="${selected.photo_url}" style="width:100%;height:100%;object-fit:cover;" />`
              : `<div style="font-size:30px;color:rgba(255,255,255,.5);">👤</div>`}
          </div>
          <div style="display:flex;gap:1px;">
            ${[2,1,3,1,2,1,3,2,1,2].map(h => `<div style="width:2px;height:${h*6}px;background:rgba(255,255,255,.7);border-radius:1px;"></div>`).join('')}
          </div>
        </div>
        <div style="flex:1;display:flex;flex-direction:column;justify-content:space-between;padding:12px 14px;">
          <div>
            <div style="font-size:7px;font-weight:700;color:${s.sidebar};text-transform:uppercase;letter-spacing:.1em;margin-bottom:1px;">STUDENT IDENTITY CARD</div>
            <div style="font-size:15px;font-weight:800;color:#111827;line-height:1.2;margin-bottom:8px;">${name}</div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:2px 8px;">
              ${[
                ['Class',    selected?.class_name   || '—'],
                ['Section', selected?.section_name  || '—'],
                ['Adm No.', selected?.admission_no  || '—'],
                ['Roll No.', selected?.roll_no      || '—'],
                ['DOB',     (selected?.date_of_birth||'—').split('T')[0]],
                ['Blood',    selected?.blood_group  || '—'],
              ].map(([k,v]) => `
                <div style="line-height:1.7;">
                  <span style="font-size:8px;color:#9CA3AF;">${k}: </span>
                  <span style="font-size:9px;color:#374151;font-weight:600;">${v}</span>
                </div>`).join('')}
            </div>
          </div>
          <div style="background:${s.bg};border-radius:8px;padding:5px 10px;display:flex;justify-content:space-between;align-items:center;">
            <div>
              <div style="font-size:8px;font-weight:700;color:${s.sidebar};">${school?.schoolName||'School Name'}</div>
              <div style="font-size:7px;color:#6B7280;">${school?.phone||''}</div>
            </div>
            <div style="text-align:right;">
              <div style="font-size:7px;color:#6B7280;">Valid: 2025–26</div>
              <div style="font-size:8px;font-weight:700;color:${s.accent};">✦ EduErpee</div>
            </div>
          </div>
        </div>
      </div>`;

    const backHTML = `
      <div style="width:340px;height:200px;border-radius:14px;overflow:hidden;font-family:'Plus Jakarta Sans',Arial,sans-serif;background:#fff;box-shadow:0 4px 20px rgba(0,0,0,.15);display:flex;flex-direction:column;justify-content:space-between;flex-shrink:0;border:1px solid #E5E7EB;">
        <div style="background:${s.sidebar};padding:10px 16px;">
          <div style="color:rgba(255,255,255,.7);font-size:7px;text-transform:uppercase;letter-spacing:.1em;">Student Identity Card — Back</div>
          <div style="color:#fff;font-size:11px;font-weight:700;">${school?.schoolName||'School Name'}</div>
        </div>
        <div style="padding:10px 16px;flex:1;display:flex;flex-direction:column;justify-content:center;gap:5px;">
          ${[
            ['📍', school?.address||'School Address'],
            ['📞', school?.phone||'Phone Number'],
            ['✉️', school?.email||'school@email.com'],
            ['🌐', school?.website||'www.school.edu.in'],
          ].map(([icon,val]) => `
            <div style="display:flex;gap:6px;align-items:center;font-size:9px;color:#374151;">
              <span style="font-size:10px;">${icon}</span><span>${val}</span>
            </div>`).join('')}
        </div>
        <div style="background:${s.bg};padding:6px 16px;display:flex;justify-content:space-between;align-items:center;">
          <div style="font-size:8px;color:${s.sidebar};font-weight:600;">If found, please return to school</div>
          <div style="font-size:8px;color:${s.sidebar};">Session: 2025-26</div>
        </div>
      </div>`;

    const win = window.open('', '_blank', 'width=700,height=650');
    win.document.write(`<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8"/>
  <title>ID Card — ${name}</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;600;700;800&display=swap');
    * { margin:0; padding:0; box-sizing:border-box; -webkit-print-color-adjust:exact !important; print-color-adjust:exact !important; color-adjust:exact !important; }
    body { font-family:'Plus Jakarta Sans',Arial,sans-serif; background:#fff; display:flex; flex-direction:column; align-items:center; gap:24px; padding:24px; }
    .label { font-size:11px; font-weight:700; color:#6B7280; text-transform:uppercase; letter-spacing:.06em; margin-bottom:8px; text-align:center; }
    @media print {
      @page { size: 4in 5.5in; margin: 5mm; }
      body { padding: 5mm; gap: 16px; }
    }
  </style>
</head>
<body>
  <div class="label">— FRONT SIDE —</div>
  ${frontHTML}
  <div class="label">— BACK SIDE —</div>
  ${backHTML}
  <script>
    // Small delay to let fonts load before printing
    window.onload = function() {
      setTimeout(function() { window.print(); }, 800);
    };
  </script>
</body>
</html>`);
    win.document.close();
  };

  return (
    <div>
      {/* Header */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:18 }}>
        <div>
          <h2 style={{ fontSize:20, fontWeight:700, color:'#111827' }}>🪪 ID Card Generator</h2>
          <p style={{ fontSize:12, color:'#6B7280', marginTop:2 }}>Design, preview and print student identity cards</p>
        </div>
        <div style={{ display:'flex', gap:10 }}>
          <button onClick={() => setShowBulk(true)} style={{ padding:'9px 16px', border:'1.5px solid #1E1B4B', borderRadius:9, background:'#EDE9F8', color:'#1E1B4B', fontSize:12, fontWeight:700, cursor:'pointer' }}>📄 Bulk Print</button>
          {selected && <button onClick={handlePrint} style={{ padding:'9px 20px', background:'#1E1B4B', color:'#fff', border:'none', borderRadius:9, fontSize:13, fontWeight:700, cursor:'pointer' }}>🖨️ Print Card</button>}
        </div>
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'300px 1fr', gap:20 }}>

        {/* LEFT — style + search */}
        <div>
          {/* Style picker */}
          <div style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:12, padding:14, marginBottom:14 }}>
            <div style={{ fontSize:12, fontWeight:700, color:'#374151', marginBottom:10 }}>🎨 Card Style</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8 }}>
              {Object.entries(STYLES).map(([id, s]) => (
                <div key={id} onClick={() => setCardStyle(id)}
                  style={{ padding:'8px 10px', borderRadius:9, cursor:'pointer', border:'2px solid ' + (cardStyle===id?s.sidebar:'#E5E7EB'), background:cardStyle===id?s.bg:'#F9FAFB', display:'flex', alignItems:'center', gap:8, transition:'all .15s' }}>
                  <div style={{ width:14, height:14, borderRadius:'50%', background:s.sidebar, flexShrink:0 }}/>
                  <span style={{ fontSize:11, fontWeight:600, color:'#374151' }}>{s.name}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Student search list */}
          <div style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:12, overflow:'hidden' }}>
            <div style={{ padding:'10px 12px', borderBottom:'0.5px solid #F3F4F6' }}>
              <input placeholder="🔍 Search students…" value={search} onChange={e => setSearch(e.target.value)}
                style={{ width:'100%', padding:'8px 10px', border:'1.5px solid #E5E7EB', borderRadius:8, fontSize:12, outline:'none', boxSizing:'border-box' }}/>
            </div>
            <div style={{ maxHeight:420, overflowY:'auto' }}>
              {loading && <div style={{ padding:20, textAlign:'center', color:'#9CA3AF' }}>⏳ Loading…</div>}
              {!loading && filtered.length === 0 && <div style={{ padding:20, textAlign:'center', color:'#9CA3AF', fontSize:12 }}>No students found</div>}
              {!loading && filtered.map(s => {
                const name = ((s.first_name||'') + ' ' + (s.last_name||'')).trim();
                const active = selected?.id === s.id;
                return (
                  <div key={s.id} onClick={() => setSelected(s)}
                    style={{ padding:'10px 14px', borderBottom:'0.5px solid #F9FAFB', cursor:'pointer', background:active?'#EDE9F8':'transparent', borderLeft:active?'3px solid #7C3AED':'3px solid transparent', transition:'all .1s' }}
                    onMouseEnter={e => { if(!active) e.currentTarget.style.background='#F5F3FF'; }}
                    onMouseLeave={e => { if(!active) e.currentTarget.style.background='transparent'; }}>
                    <div style={{ display:'flex', alignItems:'center', gap:9 }}>
                      {s.photo_url
                        ? <img src={s.photo_url} alt="" style={{ width:34, height:34, borderRadius:8, objectFit:'cover', flexShrink:0, border:'1.5px solid #E5E7EB' }}/>
                        : <div style={{ width:34, height:34, borderRadius:8, background:'#EDE9F8', display:'flex', alignItems:'center', justifyContent:'center', fontSize:13, fontWeight:700, color:'#1E1B4B', flexShrink:0 }}>{name[0]||'?'}</div>}
                      <div>
                        <div style={{ fontSize:12, fontWeight:600, color:'#111827' }}>{name}</div>
                        <div style={{ fontSize:10, color:'#9CA3AF' }}>{s.admission_no||s.adm||''} · {s.class_name||s.cls||''}</div>
                        {s.photo_url && <div style={{ fontSize:9, color:'#065F46', fontWeight:600 }}>✅ Photo</div>}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* RIGHT — Preview */}
        {!selected ? (
          <div style={{ background:'#fff', border:'2px dashed #E5E7EB', borderRadius:14, padding:60, textAlign:'center', color:'#9CA3AF', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center' }}>
            <div style={{ fontSize:60, marginBottom:16 }}>🪪</div>
            <div style={{ fontSize:16, fontWeight:700, color:'#6B7280', marginBottom:8 }}>Select a student</div>
            <div style={{ fontSize:13 }}>to preview and print their ID card</div>
          </div>
        ) : (
          <div>
            {/* Student info */}
            <div style={{ background:'#EDE9F8', borderRadius:12, padding:'12px 16px', marginBottom:18, display:'flex', alignItems:'center', gap:12 }}>
              {selected.photo_url
                ? <img src={selected.photo_url} alt="" style={{ width:48, height:48, borderRadius:10, objectFit:'cover', flexShrink:0 }}/>
                : <div style={{ width:48, height:48, borderRadius:10, background:'#C4B5FD', display:'flex', alignItems:'center', justifyContent:'center', fontSize:20 }}>👤</div>}
              <div>
                <div style={{ fontWeight:800, color:'#1E1B4B', fontSize:15 }}>
                  {((selected.first_name||'') + ' ' + (selected.last_name||'')).trim()}
                </div>
                <div style={{ fontSize:12, color:'#6B7280' }}>
                  {selected.admission_no||selected.adm} · {selected.class_name||selected.cls} {selected.section_name||selected.sec}
                </div>
                {!selected.photo_url && (
                  <div style={{ fontSize:10, color:'#92400E', marginTop:3 }}>
                    ⚠️ No photo uploaded — showing placeholder. Upload photo from Students page.
                  </div>
                )}
              </div>
            </div>

            {/* Front card */}
            <div style={{ marginBottom:20 }}>
              <div style={{ fontSize:12, fontWeight:700, color:'#374151', marginBottom:10 }}>🪪 Front Side:</div>
              <CardFront student={selected} style={cardStyle} school={school}/>
            </div>

            {/* Back card */}
            <div style={{ marginBottom:24 }}>
              <div style={{ fontSize:12, fontWeight:700, color:'#374151', marginBottom:10 }}>↩ Back Side:</div>
              <CardBack student={selected} style={cardStyle} school={school}/>
            </div>

            {/* Print button */}
            <div style={{ display:'flex', gap:12 }}>
              <button onClick={handlePrint}
                style={{ flex:1, padding:'13px', background:'#1E1B4B', color:'#fff', border:'none', borderRadius:10, fontSize:14, fontWeight:700, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:8 }}>
                🖨️ Preview &amp; Print ID Card
              </button>
            </div>
          </div>
        )}
      </div>

      {/* ── PRINT PREVIEW MODAL ── */}
      {showPrint && selected && (
        <div style={{ position:'fixed', inset:0, background:'rgba(15,23,42,.7)', zIndex:600, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div style={{ background:'#fff', borderRadius:18, width:700, maxHeight:'92vh', overflow:'auto', display:'flex', flexDirection:'column' }}>
            {/* Header */}
            <div style={{ padding:'16px 24px', borderBottom:'1px solid #E5E7EB', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
              <div>
                <div style={{ fontWeight:800, fontSize:16 }}>🖨️ Print Preview</div>
                <div style={{ fontSize:12, color:'#6B7280', marginTop:2 }}>{((selected.first_name||'') + ' ' + (selected.last_name||'')).trim()} · {selected.admission_no||selected.adm}</div>
              </div>
              <button onClick={() => setShowPrint(false)} style={{ background:'#F3F4F6', border:'none', borderRadius:8, width:34, height:34, cursor:'pointer', fontSize:18 }}>✕</button>
            </div>

            {/* Print content */}
            <div style={{ flex:1, overflowY:'auto', padding:24, background:'#F3F4F6' }}>
              {/* This div is what gets printed */}
              <div ref={printRef}>
                <div style={{ display:'flex', flexDirection:'column', gap:20, alignItems:'center' }}>
                  {/* Front */}
                  <div>
                    <div style={{ fontSize:11, fontWeight:700, color:'#6B7280', textAlign:'center', marginBottom:8, textTransform:'uppercase', letterSpacing:'.06em' }}>— Front Side —</div>
                    <CardFront student={selected} style={cardStyle} school={school}/>
                  </div>
                  {/* Back */}
                  <div>
                    <div style={{ fontSize:11, fontWeight:700, color:'#6B7280', textAlign:'center', marginBottom:8, textTransform:'uppercase', letterSpacing:'.06em' }}>— Back Side —</div>
                    <CardBack student={selected} style={cardStyle} school={school}/>
                  </div>
                </div>
              </div>
            </div>

            {/* Footer */}
            <div style={{ padding:'16px 24px', borderTop:'1px solid #E5E7EB', display:'flex', gap:12, justifyContent:'flex-end', background:'#fff', flexShrink:0 }}>
              <div style={{ flex:1, display:'flex', alignItems:'center', gap:8, fontSize:12, color:'#6B7280' }}>
                <span>🎨 Style: <strong>{STYLES[cardStyle]?.name}</strong></span>
                {selected.photo_url ? <span style={{ color:'#065F46', fontWeight:600 }}>✅ Photo included</span> : <span style={{ color:'#92400E' }}>⚠️ No photo</span>}
              </div>
              <button onClick={() => setShowPrint(false)} style={{ padding:'10px 18px', border:'1.5px solid #E5E7EB', borderRadius:9, background:'#fff', fontSize:13, cursor:'pointer' }}>Cancel</button>
              <button onClick={doPrint}
                style={{ padding:'10px 24px', background:'#1E1B4B', color:'#fff', border:'none', borderRadius:9, fontSize:13, fontWeight:700, cursor:'pointer', display:'flex', alignItems:'center', gap:8 }}>
                🖨️ Print Now
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── BULK PRINT MODAL ── */}
      {showBulk && (
        <div style={{ position:'fixed', inset:0, background:'rgba(15,23,42,.45)', zIndex:500, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div style={{ background:'#fff', borderRadius:18, width:460, overflow:'hidden' }}>
            <div style={{ padding:'16px 20px', borderBottom:'0.5px solid #E5E7EB', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <div style={{ fontWeight:700, fontSize:15 }}>📄 Bulk Print ID Cards</div>
              <button onClick={() => setShowBulk(false)} style={{ background:'#F3F4F6', border:'none', borderRadius:8, width:32, height:32, cursor:'pointer', fontSize:16 }}>✕</button>
            </div>
            <div style={{ padding:22 }}>
              <div style={{ marginBottom:14 }}>
                <label style={{ display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 }}>Filter by Class</label>
                <select value={bulkClass} onChange={e => setBulkClass(e.target.value)}
                  style={{ width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none' }}>
                  <option value="">All Classes ({students.length} students)</option>
                  {classes.map(c => {
                    const cnt = students.filter(s => s.class_name===c).length;
                    return <option key={c} value={c}>{c} ({cnt} students)</option>;
                  })}
                </select>
              </div>
              <div style={{ padding:'10px 12px', background:'#EDE9F8', borderRadius:9, marginBottom:14, fontSize:12, color:'#1E1B4B' }}>
                Will print <strong>{bulkClass ? students.filter(s=>s.class_name===bulkClass).length : students.length}</strong> ID cards
              </div>
              <div style={{ display:'flex', gap:10, justifyContent:'flex-end' }}>
                <button onClick={() => setShowBulk(false)} style={{ padding:'10px 16px', border:'1.5px solid #E5E7EB', borderRadius:9, background:'#fff', fontSize:13, cursor:'pointer' }}>Cancel</button>
                <button onClick={() => { toast.success('Opening print dialog…'); setShowBulk(false); }}
                  style={{ padding:'10px 20px', background:'#1E1B4B', color:'#fff', border:'none', borderRadius:9, fontSize:13, fontWeight:700, cursor:'pointer' }}>
                  🖨️ Print All
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
